'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { useCart } from '@/contexts/CartContext';
import { PRODUCTS } from '@/data/products';
import { Product } from '@/types/shop';

export default function CartContent() {
  const { cart, removeItem, updateQuantity, clearCart } = useCart();
  const [products, setProducts] = useState<Record<string, Product>>({});
  const router = useRouter();

  useEffect(() => {
    // Map cart items to products
    const productMap: Record<string, Product> = {};
    cart.items.forEach(item => {
      const product = PRODUCTS.find(p => p.id === item.productId);
      if (product) {
        productMap[item.productId] = product;
      }
    });
    setProducts(productMap);
  }, [cart.items]);

  const shippingCost = cart.total >= 50 ? 0 : 6.95;
  const totalWithShipping = cart.total + shippingCost;

  if (cart.items.length === 0) {
    return (
      <div className="min-h-screen bg-gray-50">
        <div className="container mx-auto px-4 py-16">
          <div className="max-w-md mx-auto text-center">
            <div className="text-6xl mb-4">🛒</div>
            <h1 className="text-3xl font-bold text-gray-900 mb-4">
              Uw winkelwagen is leeg
            </h1>
            <p className="text-gray-600 mb-8">
              Voeg producten toe om te beginnen met winkelen
            </p>
            <Link
              href="/shop"
              className="inline-block bg-blue-600 text-white px-8 py-3 rounded-lg font-medium hover:bg-blue-700 transition-colors"
            >
              Naar de shop
            </Link>
          </div>
        </div>
      </div>
    );
  }

  const productIcon = (category: string) => 
    category === 'onderhoud-reiniging' ? '🧴' :
    category === 'tochtwering-isolatie' ? '🔧' :
    category === 'raam-accessoires' ? '🪟' :
    category === 'deur-accessoires' ? '🚪' :
    '📦';

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="container mx-auto px-4 py-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-8">Winkelwagen</h1>

        <div className="grid lg:grid-cols-3 gap-8">
          {/* Cart Items */}
          <div className="lg:col-span-2 space-y-4">
            {cart.items.map((item) => {
              const product = products[item.productId];
              if (!product) return null;

              return (
                <div
                  key={item.productId}
                  className="bg-white rounded-lg shadow-md p-6 flex gap-6"
                >
                  <div className="w-24 h-24 flex-shrink-0 bg-gradient-to-br from-blue-50 to-gray-100 rounded-lg flex items-center justify-center text-4xl">
                    {productIcon(product.category)}
                  </div>
                  <div className="flex-1">
                    <h3 className="font-bold text-lg text-gray-900 mb-1">
                      {product.name}
                    </h3>
                    <p className="text-sm text-gray-500 mb-3">
                      {product.brand} • SKU: {product.sku}
                    </p>
                    <div className="flex items-center gap-4">
                      <div className="flex items-center border border-gray-300 rounded-lg">
                        <button
                          onClick={() => updateQuantity(item.productId, item.quantity - 1)}
                          className="px-3 py-1 hover:bg-gray-100 transition-colors"
                        >
                          -
                        </button>
                        <span className="px-4 py-1 border-x border-gray-300">
                          {item.quantity}
                        </span>
                        <button
                          onClick={() => updateQuantity(item.productId, item.quantity + 1)}
                          className="px-3 py-1 hover:bg-gray-100 transition-colors"
                        >
                          +
                        </button>
                      </div>
                      <button
                        onClick={() => removeItem(item.productId)}
                        className="text-red-600 hover:text-red-700 text-sm font-medium"
                      >
                        Verwijderen
                      </button>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-2xl font-bold text-blue-600">
                      €{(item.price * item.quantity).toFixed(2)}
                    </p>
                    <p className="text-sm text-gray-500">
                      €{item.price.toFixed(2)} per stuk
                    </p>
                  </div>
                </div>
              );
            })}

            <button
              onClick={clearCart}
              className="text-red-600 hover:text-red-700 text-sm font-medium"
            >
              Winkelwagen legen
            </button>
          </div>

          {/* Order Summary */}
          <div className="lg:col-span-1">
            <div className="bg-white rounded-lg shadow-md p-6 sticky top-4">
              <h2 className="text-xl font-bold text-gray-900 mb-4">
                Overzicht
              </h2>

              <div className="space-y-3 mb-6">
                <div className="flex justify-between text-gray-600">
                  <span>Subtotaal</span>
                  <span>€{cart.total.toFixed(2)}</span>
                </div>
                <div className="flex justify-between text-gray-600">
                  <span>Verzendkosten</span>
                  <span>
                    {shippingCost === 0 ? (
                      <span className="text-green-600 font-medium">Gratis</span>
                    ) : (
                      `€${shippingCost.toFixed(2)}`
                    )}
                  </span>
                </div>
                {cart.total < 50 && (
                  <div className="bg-blue-50 border border-blue-200 rounded-lg p-3">
                    <p className="text-sm text-blue-800">
                      Nog €{(50 - cart.total).toFixed(2)} tot gratis verzending! 🚚
                    </p>
                  </div>
                )}
                <div className="border-t pt-3 flex justify-between text-lg font-bold">
                  <span>Totaal</span>
                  <span className="text-blue-600">
                    €{totalWithShipping.toFixed(2)}
                  </span>
                </div>
              </div>

              <Link
                href="/contact"
                className="block w-full bg-blue-600 text-white text-center py-3 rounded-lg font-bold hover:bg-blue-700 transition-colors mb-3"
              >
                Bestelling Plaatsen
              </Link>

              <p className="text-xs text-center text-gray-500 mb-3">
                Neem contact op om uw bestelling af te ronden
              </p>

              <Link
                href="/shop"
                className="block w-full text-center text-blue-600 hover:underline"
              >
                Verder winkelen
              </Link>

              <div className="mt-6 pt-6 border-t space-y-2 text-sm text-gray-600">
                <p>✓ Veilig betalen</p>
                <p>✓ 14 dagen retourrecht</p>
                <p>✓ Gratis verzending vanaf €50</p>
                <p>✓ Besteld voor 15:00, morgen in huis</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
